import React, { useState } from 'react';
import './App.css';
import KLineChart from './components/KLineChart';
import UASTLChart from './components/UASTLChart';

function App() {
    const [selectedRange, setSelectedRange] = useState(null);

    return (
        <div className="app-container">
            <div className="charts-container" style={{ width: '75%', float: 'left' }}>
                <div className="kline-chart-container">
                    <KLineChart onRangeChange={setSelectedRange} />
                </div>
                <div className="uastl-chart-container">
                    <UASTLChart range={selectedRange} />
                </div>
            </div>
            <div className="right-panel" style={{ width: '25%', float: 'right' }}>
                {/* 右側面板內容 */}
            </div>
        </div>
    );
}

export default App;
